import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer,
  PieChart, Pie, Cell, Legend
} from 'recharts';
import api from '../utils/api';
import { useAuth } from '../context/AuthContext';
import { STATUS_CONFIG, StatusBadge, PriorityBadge, formatDate } from '../utils/statusHelpers';
import Sidebar from '../components/common/Sidebar';

const COLORS = ['#ff6b35','#3b82f6','#22c55e','#f59e0b','#a855f7','#06b6d4','#ef4444','#10b981'];

const KpiCard = ({ label, value, unit, accent, sub }) => (
  <div className="kpi-card" style={{ '--accent': accent || 'var(--accent)' }}>
    <div className="kpi-value" style={{ color: accent || 'var(--text-primary)' }}>
      {value ?? <span className="spinner" style={{ width: 24, height: 24 }}/>}
      {unit && <span style={{ fontSize: '1rem', fontWeight: 400, color: 'var(--text-secondary)', marginLeft: '0.3rem' }}>{unit}</span>}
    </div>
    <div className="kpi-label">{label}</div>
    {sub && <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)', marginTop: '0.25rem' }}>{sub}</div>}
  </div>
);

const toNumber = (value) => parseInt(value || 0, 10);

const CustomTooltip = ({ active, payload, label }) => {
  if (!active || !payload?.length) return null;
  return (
    <div style={{ background: 'var(--bg-card)', border: '1px solid var(--border-light)', borderRadius: 6, padding: '0.6rem 0.85rem', fontSize: '0.8rem' }}>
      <div style={{ color: 'var(--text-muted)', marginBottom: '0.25rem' }}>{label}</div>
      {payload.map((p, i) => (
        <div key={i} style={{ color: p.fill || p.color || 'var(--accent)' }}>{p.name}: <strong>{p.value}</strong></div>
      ))}
    </div>
  );
};

export default function DashboardPage() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [recentRequests, setRecentRequests] = useState([]);

  useEffect(() => {
    const fetchAll = async () => {
      try {
        const [dashRes, reqRes] = await Promise.all([
          api.get('/dashboard/operational'),
          api.get('/requests?limit=8&sort=created_at&order=DESC'),
        ]);
        setData(dashRes.data);
        setRecentRequests(reqRes.data.requests);
      } catch (err) { console.error(err); }
      setLoading(false);
    };
    fetchAll();
  }, []);

  const pieData = data?.statusSplit?.map(r => ({
    name: STATUS_CONFIG[r.status]?.label || r.status,
    value: parseInt(r.count),
    color: STATUS_CONFIG[r.status]?.color || '#64748b',
  })) || [];

  const priorityData = data?.prioritySplit?.map(r => ({
    name: r.priority ? r.priority.charAt(0).toUpperCase() + r.priority.slice(1) : 'Unknown',
    count: parseInt(r.count),
    fill: r.priority === 'critical' ? '#ef4444' : r.priority === 'high' ? '#f59e0b' : r.priority === 'normal' ? '#3b82f6' : '#64748b',
  })) || [];

  if (loading) return (
    <div className="page"><Sidebar/>
      <div className="main-content" style={{ display:'flex', alignItems:'center', justifyContent:'center' }}>
        <span className="spinner" style={{ width: 36, height: 36 }}/>
      </div>
    </div>
  );

  return (
    <div className="page">
      <Sidebar />
      <div className="main-content">
        <div className="page-header">
          <div>
            <div style={{ color: 'var(--text-muted)', fontSize: '0.72rem', marginBottom: '0.25rem' }}>
              Dashboards / Operational Dashboard
            </div>
            <h1 style={{ fontSize: '1.3rem', fontFamily: 'var(--font-heading)' }}>Operational Dashboard</h1>
            <p style={{ color: 'var(--text-muted)', fontSize: '0.8rem', marginTop: '0.2rem' }}>
              Real-time overview — {user?.firstName} {user?.lastName}
            </p>
          </div>
          {['coordinator','administrator'].includes(user?.role) && (
            <button className="btn btn-primary" onClick={() => navigate('/requests/new')}>+ New Request</button>
          )}
        </div>

        <div className="page-body">
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(170px, 1fr))', gap: '1rem', marginBottom: '1.5rem' }}>
            <KpiCard
              label="Awaiting Approval"
              value={data?.awaitingApprovalCount ?? 0}
              accent={(data?.awaitingApprovalCount ?? 0) > 0 ? 'var(--yellow)' : 'var(--green)'}
            />
            <KpiCard
              label="Awaiting Requester Confirmation"
              value={data?.awaitingRequesterConfirmationCount ?? 0}
              accent={(data?.awaitingRequesterConfirmationCount ?? 0) > 0 ? 'var(--cyan)' : 'var(--green)'}
            />
            <KpiCard
              label="Rework Required"
              value={data?.reworkRequiredCount ?? 0}
              accent={(data?.reworkRequiredCount ?? 0) > 0 ? 'var(--accent)' : 'var(--green)'}
            />
            <KpiCard
              label="Low Stock Alerts"
              value={data?.lowStockAlertsCount ?? 0}
              accent={(data?.lowStockAlertsCount ?? 0) > 0 ? 'var(--yellow)' : 'var(--green)'}
            />
            <KpiCard
              label="Overdue Requests"
              value={data?.overdueCount ?? 0}
              accent={(data?.overdueCount ?? 0) > 0 ? 'var(--red)' : 'var(--green)'}
              sub={(data?.overdueCount ?? 0) > 0 ? 'Requires attention' : 'All on track'}
            />
          </div>

          <div className="grid-2" style={{ marginBottom: '1.5rem' }}>
            <div className="card">
              <h3 style={{ fontSize: '0.8rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '1rem' }}>Status Distribution</h3>
              {pieData.length > 0 ? (
                <ResponsiveContainer width="100%" height={220}>
                  <PieChart>
                    <Pie data={pieData} cx="45%" cy="50%" innerRadius={55} outerRadius={85} dataKey="value" paddingAngle={2}>
                      {pieData.map((entry, i) => <Cell key={i} fill={entry.color}/>)}
                    </Pie>
                    <Tooltip content={<CustomTooltip/>}/>
                    <Legend iconType="circle" iconSize={8} wrapperStyle={{ fontSize: '0.75rem', paddingLeft: '1rem' }}/>
                  </PieChart>
                </ResponsiveContainer>
              ) : <div className="empty-state" style={{ padding: '2rem' }}><p>No data yet</p></div>}
            </div>

            <div className="card">
              <h3 style={{ fontSize: '0.8rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '1rem' }}>Priority Split</h3>
              {priorityData.length > 0 ? (
                <ResponsiveContainer width="100%" height={220}>
                  <BarChart data={priorityData} barSize={28}>
                    <XAxis dataKey="name" tick={{ fill: 'var(--text-muted)', fontSize: 12 }} axisLine={false} tickLine={false}/>
                    <YAxis tick={{ fill: 'var(--text-muted)', fontSize: 11 }} axisLine={false} tickLine={false} width={28}/>
                    <Tooltip content={<CustomTooltip/>}/>
                    <Bar dataKey="count" radius={[4,4,0,0]}>
                      {priorityData.map((entry, i) => <Cell key={i} fill={entry.fill}/>)}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
              ) : <div className="empty-state" style={{ padding: '2rem' }}><p>No data yet</p></div>}
            </div>
          </div>

          <div className="grid-2" style={{ marginBottom: '1.5rem' }}>
            <div className="card">
              <h3 style={{ fontSize: '0.8rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '1rem' }}>Technician Schedule</h3>
              {data?.technicianSchedule?.length > 0 ? (
                <div className="table-container">
                  <table>
                    <thead>
                      <tr>
                        <th>Technician</th>
                        <th>Assigned Requests</th>
                        <th>In Progress Requests</th>
                        <th>Planned Requests</th>
                      </tr>
                    </thead>
                    <tbody>
                      {data.technicianSchedule.map(row => (
                        <tr key={row.id}>
                          <td style={{ fontWeight: 600 }}>{row.technician}</td>
                          <td>{toNumber(row.assigned_requests)}</td>
                          <td>{toNumber(row.in_progress_requests)}</td>
                          <td>{toNumber(row.planned_requests)}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              ) : <div className="empty-state" style={{ padding: '1rem' }}><p>No technician schedule</p></div>}
            </div>

            <div className="card">
              <h3 style={{ fontSize: '0.8rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '1rem' }}>Printer Schedule</h3>
              {data?.printerSchedule?.length > 0 ? (
                <div className="table-container">
                  <table>
                    <thead>
                      <tr>
                        <th>Printer</th>
                        <th>Current Jobs</th>
                        <th>Planned Jobs</th>
                        <th>Availability</th>
                      </tr>
                    </thead>
                    <tbody>
                      {data.printerSchedule.map(row => {
                        const availability = row.availability || 'unknown';
                        const availabilityColor = availability === 'available'
                          ? 'var(--green)'
                          : availability === 'maintenance'
                            ? 'var(--yellow)'
                            : availability === 'offline'
                              ? 'var(--red)'
                              : 'var(--cyan)';
                        return (
                          <tr key={row.id}>
                            <td style={{ fontWeight: 600 }}>{row.printer}</td>
                            <td>{toNumber(row.current_jobs)}</td>
                            <td>{toNumber(row.planned_jobs)}</td>
                            <td>
                              <span style={{
                                color: availabilityColor,
                                fontSize: '0.72rem',
                                fontWeight: 700,
                                textTransform: 'uppercase',
                              }}>
                                {availability.replace(/_/g, ' ')}
                              </span>
                            </td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
                </div>
              ) : <div className="empty-state" style={{ padding: '1rem' }}><p>No printer schedule</p></div>}
            </div>
          </div>

          <div className="card">
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
              <h3 style={{ fontSize: '0.8rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.08em' }}>Recent Requests</h3>
              <button className="btn btn-ghost btn-sm" onClick={() => navigate('/requests')}>View all →</button>
            </div>
            {recentRequests.length === 0 ? (
              <div className="empty-state" style={{ padding: '1.5rem' }}><p>No requests yet</p></div>
            ) : (
              <div className="table-container">
                <table>
                  <thead><tr><th>ID</th><th>Title</th><th>Status</th><th>Priority</th><th>Requester</th><th>Due Date</th></tr></thead>
                  <tbody>
                    {recentRequests.map(r => (
                      <tr key={r.id} style={{ cursor: 'pointer' }} onClick={() => navigate(`/requests/${r.id}`)}>
                        <td style={{ fontFamily: 'var(--font-mono)', fontSize: '0.78rem', color: 'var(--accent)', fontWeight: 600 }}>{r.request_number}</td>
                        <td style={{ maxWidth: 220, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', fontSize: '0.83rem' }}>{r.title}</td>
                        <td><StatusBadge status={r.status}/></td>
                        <td><PriorityBadge priority={r.priority}/></td>
                        <td style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>{r.requester_name || '—'}</td>
                        <td style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>{formatDate(r.approved_due_date)}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
